+<script>
+/* ═══════════════════════════════════════════
+   DB & CONSTANTS
+═══════════════════════════════════════════ */
+const DB_KEY = 'MY_NEXUS_V3_MONSTER';
+window.DB_KEY = DB_KEY;
+
+var currentStoryFilter = window.currentStoryFilter || '전체';
+window.currentStoryFilter = currentStoryFilter;
+
+const WORLD_ASSETS = {
