+  story: './assets/world/story_land_map.png',
+  voice: './assets/world/voice_land_map.png'
+};
+
+const WORLD_ZONES = {
+  game:    { x: '29%', y: '23%', w:'30%', h:'20%', label: '게임랜드',   emoji: '🎮' },
+  numbers: { x: '72%', y: '24%', w:'30%', h:'21%', label: '숫자놀이터', emoji: '🔢' },
+  letters: { x: '27%', y: '47%', w:'32%', h:'22%', label: '글자놀이터', emoji: '🔤' },
+  cars:    { x: '73%', y: '49%', w:'32%', h:'24%', label: '자동차마을', emoji: '🚗' },
+  story:   { x: '29%', y: '74%', w:'34%', h:'24%', label: '동화나라',   emoji: '🏰' },
+  voice:   { x: '72%', y: '76%', w:'32%', h:'23%', label: '말하기광장', emoji: '🎤' },
+  station: { x: '50%', y: '88%', label: '중앙역', emoji: '🚉' }
+};
+
+const CARS = ['🚗','🚕','🚙','🚌','🚒','🚑','🚓','🚚','🚜','🏎️','🚛','🚐'];
+let garageCleanup = null;
+
+const DEFAULT_DB = {
+  version: '2.0.0',
+  progress: { level:1, exp:0 },
+  playground: {
+    collection: [],
+    storyWorld: {
+      savedStories: [], characters: [], readingHistory: [], favoriteStoryIds: [], currentStory: null,
+      settings: { heroName: '시현', defaultTheme: '자동차', defaultLength: 'long', defaultTone: 'dad' }
+    }
+  },
+  settings: {
+    voiceGuide: { enabled:true, autoRead:true, rate:0.85, pitch:1.1 },
+    ai: { model:'gemini-3.0-flash' }
+  }
+};
+
+/* ═══════════════════════════════════════════
+   UTILITY & DB FUNCTIONS
+═══════════════════════════════════════════ */
+function clone(v){ return JSON.parse(JSON.stringify(v)); }
+
+function mergeDefaults(target, defaults){
+  if(!target || typeof target !== 'object') target = {};
+  Object.keys(defaults).forEach(key => {
+    const sv = defaults[key], tv = target[key];
+    if(Array.isArray(sv)){ if(!Array.isArray(tv)) target[key]=[]; return; }
+    if(sv && typeof sv === 'object'){ target[key]=mergeDefaults(tv,sv); return; }
+    if(tv===undefined||tv===null) target[key]=sv;
+  });
+  return target;
+}
+
+function loadStoredDB(){
+  try{
+    const raw = localStorage.getItem(DB_KEY);
+    if(!raw) return JSON.parse(JSON.stringify(DEFAULT_DB));
+    return mergeDefaults(JSON.parse(raw), JSON.parse(JSON.stringify(DEFAULT_DB)));
+  }catch(e){ 
+    return JSON.parse(JSON.stringify(DEFAULT_DB)); 
+  }
+}
+
+function loadDB(){
+  window.db = loadStoredDB();
+  return window.db;
+}
+
+let db = loadDB();
+window.db = db;
+
+function getToday(){ return new Date().toISOString().slice(0,10); }
+
+function escapeHtml(v){
+  return String(v??'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;').replace(/'/g,'&#039;');
+}
+
+function refreshLegacyCompatibility(){
+  db.progress = db.progress||{level:1,exp:0};
+  db.playground = db.playground||{};
+  db.playground.collection = Array.isArray(db.playground.collection)?db.playground.collection:[];
+  db.playground.storyWorld = mergeDefaults(db.playground.storyWorld, clone(DEFAULT_DB.playground.storyWorld));
+  db.settings = mergeDefaults(db.settings, clone(DEFAULT_DB.settings));
+}
+
+function save(){ 
+  refreshLegacyCompatibility(); 
+  localStorage.setItem(DB_KEY, JSON.stringify(db)); 
+}
+
+/* ═══════════════════════════════════════════
+   AUDIO & UX FUNCTIONS
+═══════════════════════════════════════════ */
+function isStoryPlaying(){ 
+  return Boolean(window.storyReadState && window.storyReadState.isReading); 
+}
+
+function speakText(text, opts={}){
+  if(!text || !('speechSynthesis' in window)) return;
+  window.speechSynthesis.cancel();
+  const u = new SpeechSynthesisUtterance(text);
+  u.lang = 'ko-KR'; 
+  u.rate = opts.rate || db.settings.voiceGuide.rate || 0.85;
+  u.pitch = opts.pitch || db.settings.voiceGuide.pitch || 1.1;
+  window.speechSynthesis.speak(u);
+}
+
+function speakGuide(text, force=false){
+  if(!force && isStoryPlaying()) return;
+  if(!db.settings.voiceGuide.enabled) return;
+  speakText(text, {rate:0.88, pitch:1.08});
+}
+
+function speakStory(text){ 
+  speakText(text, {rate:0.82, pitch:1.03}); 
+}
+
+function stopSpeaking(){ 
+  if('speechSynthesis' in window) window.speechSynthesis.cancel(); 
+}
+
+function fireConfetti(){
+  const c = document.getElementById('particle-container');
+  if(!c) return;
+  const colors=['#FFD93D','#FF7A1A','#FF4D4D','#3478F6','#8E5CFF','#00C2A8','#FF7AC8'];
+  for(let i=0;i<50;i++){
+    const d = document.createElement('div'); d.className='particle';
+    const s=Math.random()*13+8;
+    d.style.cssText=`width:${s}px;height:${s}px;left:${Math.random()*100}vw;top:-24px;background:${colors[Math.floor(Math.random()*colors.length)]};animation-duration:${Math.random()*1.4+1.4}s;animation-delay:${Math.random()*0.3}s;border-radius:${Math.random()>0.5?'50%':'4px'}`;
+    c.appendChild(d);
+    setTimeout(()=>d.remove(),3600);
+  }
+}
+
+function gainExp(amount){
+  db.progress.exp = Number(db.progress.exp||0)+Number(amount||0);
+  while(db.progress.exp>=100){
+    db.progress.level = Number(db.progress.level||1)+1; 
+    db.progress.exp -= 100;
+    fireConfetti(); 
+    speakGuide('레벨이 올라갔어! 시현이 최고!');
+  }
+  save();
+}
+
+function unlockCar(icon){
+  if(!db.playground.collection.includes(icon)){ 
+    db.playground.collection.push(icon); 
+    fireConfetti(); 
+  }
+  save();
+}
+
