+function initGarageRound(){
+  const stage   = document.getElementById('garageStage');
+  const target  = document.getElementById('garageTarget');
+  const part    = document.getElementById('garagePart');
+  const message = document.getElementById('garageMessage');
+  if(!stage||!target||!part||!message) return;
+
+  const carIcon = CARS[Math.floor(Math.random()*CARS.length)];
+  part.textContent = carIcon;
+  target.classList.remove('filled');
+  target.textContent = '여기에 쏙!';
+  message.textContent = '자동차를 빈칸까지 끌고 가 보자!';
+  part.style.cssText = 'left:20px;bottom:80px;transform:none;pointer-events:auto;';
+
+  let dragging=false, pointerId=null;
+
+  const movePart=(cx,cy)=>{
+    const sr=stage.getBoundingClientRect(), pr=part.getBoundingClientRect();
+    const nl=Math.max(0,Math.min(sr.width-pr.width,  cx-sr.left-pr.width/2));
+    const nt=Math.max(0,Math.min(sr.height-pr.height, cy-sr.top-pr.height/2));
+    part.style.left=`${nl}px`; part.style.top=`${nt}px`; part.style.bottom='auto';
+  };
+
+  const onDown=(e)=>{ dragging=true; pointerId=e.pointerId; part.setPointerCapture(e.pointerId); movePart(e.clientX,e.clientY); };
+  const onMove=(e)=>{ if(!dragging||e.pointerId!==pointerId) return; e.preventDefault(); movePart(e.clientX,e.clientY); };
+  const onUp=(e)=>{
+    if(!dragging||e.pointerId!==pointerId) return;
+    dragging=false;
+    if(part.hasPointerCapture(pointerId)) part.releasePointerCapture(pointerId);
+    const tr=target.getBoundingClientRect(), pr2=part.getBoundingClientRect();
+    const hit=!(pr2.right<tr.left-30||pr2.left>tr.right+30||pr2.bottom<tr.top-30||pr2.top>tr.bottom+30);
+    if(!hit){ message.textContent='조금만 더 가까이!'; speakGuide('조금만 더 가까이 가 볼까?'); return; }
+    target.classList.add('filled');
+    target.textContent=carIcon;
+    part.style.pointerEvents='none';
+    part.style.left=`${target.offsetLeft-part.offsetWidth/2}px`;
+    part.style.top=`${target.offsetTop-part.offsetHeight/2}px`;
+    part.style.transform='scale(1.2)';
+    message.textContent='착! 자동차가 딱 맞았어! 🎉';
+    fireConfetti();
+    speakGuide('착! 자동차가 딱 맞았어. 시현이 최고!');
+    gainExp(15);
+    unlockCar(carIcon);
+    setTimeout(()=>{ if(document.getElementById('garageStage')) initGarageRound(); }, 1400);
+  };
+
+  part.addEventListener('pointerdown',onDown);
+  part.addEventListener('pointermove',onMove);
+  part.addEventListener('pointerup',onUp);
+  part.addEventListener('pointercancel',onUp);
+  garageCleanup=()=>{
+    part.removeEventListener('pointerdown',onDown);
+    part.removeEventListener('pointermove',onMove);
+    part.removeEventListener('pointerup',onUp);
+    part.removeEventListener('pointercancel',onUp);
+  };
+}
