-function clone(v){ return JSON.parse(JSON.stringify(v)); }
-
-function mergeDefaults(target, defaults){
-  if(!target || typeof target !== 'object') target = {};
-  Object.keys(defaults).forEach(key => {
-    const sv = defaults[key], tv = target[key];
-    if(Array.isArray(sv)){ if(!Array.isArray(tv)) target[key]=[]; return; }
-    if(sv && typeof sv === 'object'){ target[key]=mergeDefaults(tv,sv); return; }
-    if(tv===undefined||tv===null) target[key]=sv;
-  });
-  return target;
-}
-
-function loadStoredDB(){
-  try{
-    const raw = localStorage.getItem(DB_KEY);
-    if(!raw) return JSON.parse(JSON.stringify(DEFAULT_DB));
-    return mergeDefaults(JSON.parse(raw), JSON.parse(JSON.stringify(DEFAULT_DB)));
-  }catch(e){ 
-    return JSON.parse(JSON.stringify(DEFAULT_DB)); 
-  }
-}
-
-function loadDB(){
-  window.db = loadStoredDB();
-  return window.db;
-}
-
-let db = loadDB();
-window.db = db;
-
-function getToday(){ return new Date().toISOString().slice(0,10); }
