-function speakText(text, opts={}){
-  if(!text || !('speechSynthesis' in window)) return;
-  window.speechSynthesis.cancel();
-  const u = new SpeechSynthesisUtterance(text);
-  u.lang = 'ko-KR'; 
-  u.rate = opts.rate || db.settings.voiceGuide.rate || 0.85;
-  u.pitch = opts.pitch || db.settings.voiceGuide.pitch || 1.1;
-  window.speechSynthesis.speak(u);
-}
-
-function speakGuide(text, force=false){
-  if(!force && isStoryPlaying()) return;
-  if(!db.settings.voiceGuide.enabled) return;
-  speakText(text, {rate:0.88, pitch:1.08});
-}
