-  for(let i=0;i<50;i++){
-    const d = document.createElement('div'); d.className='particle';
-    const s=Math.random()*13+8;
-    d.style.cssText=`width:${s}px;height:${s}px;left:${Math.random()*100}vw;top:-24px;background:${colors[Math.floor(Math.random()*colors.length)]};animation-duration:${Math.random()*1.4+1.4}s;animation-delay:${Math.random()*0.3}s;border-radius:${Math.random()>0.5?'50%':'4px'}`;
-    c.appendChild(d);
-    setTimeout(()=>d.remove(),3600);
-  }
-}
