-function gainExp(amount){
-  db.progress.exp = Number(db.progress.exp||0)+Number(amount||0);
-  while(db.progress.exp>=100){
-    db.progress.level = Number(db.progress.level||1)+1; 
-    db.progress.exp -= 100;
-    fireConfetti(); 
-    speakGuide('레벨이 올라갔어! 시현이 최고!');
-  }
-  save();
-}
