-function escapeHtml(v){
-  return String(v??'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;').replace(/'/g,'&#039;');
-}
-
-function refreshLegacyCompatibility(){
-  db.progress = db.progress||{level:1,exp:0};
-  db.playground = db.playground||{};
-  db.playground.collection = Array.isArray(db.playground.collection)?db.playground.collection:[];
-  db.playground.storyWorld = mergeDefaults(db.playground.storyWorld, clone(DEFAULT_DB.playground.storyWorld));
-  db.settings = mergeDefaults(db.settings, clone(DEFAULT_DB.settings));
-}
-
-function save(){ 
-  refreshLegacyCompatibility(); 
-  localStorage.setItem(DB_KEY, JSON.stringify(db)); 
-}
