+  db.settings=mergeDefaults(db.settings,clone(DEFAULT_DB.settings));
+  db.parentLog = db.parentLog || { daily: {} };
+  const todayStr = getToday();
+  if (!db.parentLog.daily[todayStr]) {
+    db.parentLog.daily[todayStr] = { totalMinutes: 0, timerCount: 0, landsVisited: [], storiesWatched: [] };
+  }
+}
+function save(){ refreshLegacyCompatibility(); localStorage.setItem(DB_KEY,JSON.stringify(db)); }
