+function travelToZone(zoneId){
+  const zone=WORLD_ZONES[zoneId];
+  if(!zone) return;
+
+  if(window.stopStoryReading) window.stopStoryReading(true);
+  stopSpeaking();
+  cleanupActiveGame();
+
+  // Log visited land
+  const todayStr = getToday();
+  if(db.parentLog && db.parentLog.daily[todayStr]) {
+    const landName = `${zone.emoji} ${zone.label}`;
+    if(!db.parentLog.daily[todayStr].landsVisited.includes(landName)){
+      db.parentLog.daily[todayStr].landsVisited.push(landName);
+      save();
+    }
+  }
+
+  speakGuide(`시현이가 ${zone.label}으로 걸어가요! 하나 둘, 하나 둘!`, true);
+
+  let entered = false;
+  const safeEnter = () => {
+    if(entered) return;
+    entered = true;
+    enterZone(zoneId);
+  };
+
+  const pathLen = (ZONE_PATHS[zoneId]?.length || 2) - 1;
+  const totalMs = pathLen * 620 + 400;
+
+  walkAvatarToZone(zoneId, safeEnter);
+  setTimeout(safeEnter, totalMs);
+}
+
+function walkAvatarToZone(zoneId, onComplete) {
+  const avatar = document.getElementById('sihyeonAvatar');
+  if (!avatar) { onComplete?.(); return; }
+
+  const path = ZONE_PATHS[zoneId];
+  if (!path || !path.length) { onComplete?.(); return; }
+
+  avatar.style.transition = 'none';
+  avatar.style.bottom    = 'auto';
+  avatar.style.zIndex    = '35';
+  avatar.style.left      = path[0].x;
+  avatar.style.top       = path[0].y;
+  avatar.style.transform = 'translate(-50%, -50%)';
+
+  requestAnimationFrame(() => requestAnimationFrame(() => {
+    avatar.classList.add('is-walking');
+    let idx = 1;
+
+    function step() {
+      if (idx >= path.length) {
+        avatar.classList.remove('is-walking');
+        avatar.style.transform = 'translate(-50%, -50%) scale(1.06)';
+        setTimeout(() => onComplete?.(), 150);
+        return;
+      }
+
+      const wp   = path[idx];
+      const prev = path[idx - 1];
+      const goLeft = parseFloat(wp.x) < parseFloat(prev.x);
+
+      avatar.style.transition = 'left 0.6s ease-in-out, top 0.6s ease-in-out, transform 0.25s ease';
+      avatar.style.left       = wp.x;
+      avatar.style.top        = wp.y;
+      avatar.style.transform  = `translate(-50%, -50%) scaleX(${goLeft ? -1 : 1})`;
+
+      idx++;
+      setTimeout(step, 620);
+    }
+
+    step();
+  }));
+}
