+function renderStoryGrid(theme) {
+  window.currentStoryFilter = theme || '전체';
+  window._storyPage = 1;
+  document.querySelectorAll('[data-theme]').forEach(b => {
+    b.classList.toggle('active', b.dataset.theme === (theme || '전체'));
+  });
+  const si = document.getElementById('storySearchInput');
+  if (si) si.value = '';
+  _renderStoryGridPage(theme, '');
+}
