+function _renderStoryGridPage(theme, query) {
+  const grid = document.getElementById('storyLibraryGrid');
+  if (!grid) return;
+
+  const reader = document.getElementById('storyReaderView');
+  if (reader) { reader.style.display = 'none'; reader.classList.remove('active'); }
+  grid.style.display = 'grid';
+  grid.className = 'story-card-grid storybook-featured-grid';
+
+  document.querySelector('.story-search-row')?.classList.remove('story-ui-hidden');
+  document.querySelector('.story-filter-row')?.classList.remove('story-ui-hidden');
+
+  const library = Array.isArray(window.STORY_LIBRARY) ? window.STORY_LIBRARY : [];
+  const saved   = Array.isArray(db.playground.storyWorld.savedStories) ? db.playground.storyWorld.savedStories : [];
+  const filter  = theme || window.currentStoryFilter || '전체';
+  const q       = (query || '').trim().toLowerCase();
+  const page    = window._storyPage || 1;
+
+  let list;
+  if (filter === '저장한 동화') {
+    list = saved;
+  } else {
+    list = library.filter(s => {
+      if (filter !== '전체' && !String(s.theme || '').includes(filter)) return false;
+      if (q) {
+        const haystack = (s.title + ' ' + (s.desc||'') + ' ' + (s.theme||'') + ' ' + (s.plotSeed||'')).toLowerCase();
+        return haystack.includes(q);
+      }
+      return true;
+    });
+  }
+
+  const total = list.length;
+  const paged = list.slice(0, page * STORY_PAGE_SIZE);
+
+  if (!paged.length) {
+    grid.innerHTML = `<div class="story-empty">📚 "찾는 동화"가 없어요</div>`;
+    const btn = document.getElementById('storyLoadMoreBtn');
+    if (btn) btn.style.display = 'none';
+    return;
+  }
+
+  grid.innerHTML = paged.map(story => {
+    const id    = story.id || story.savedId;
+    const emoji = _storyCoverEmoji(story.theme);
+    const img   = story.coverImage || '';
+    return `
+      <button class="storybook-book-card" type="button"
+        onclick="readStoryById('${escapeHtml(id)}')"
+        aria-label="${escapeHtml(story.title)} 읽기">
+        <span class="storybook-book-cover">
+          ${img ? `<img src="${img}" alt="${escapeHtml(story.title)}" loading="lazy" decoding="async" onerror="this.onerror=null;this.style.display='none';this.nextElementSibling.style.display='grid';">` : ''}
+          <span class="storybook-book-fallback" ${img?'style="display:none;"':''}>${emoji}</span>
+        </span>
+        <span class="storybook-book-title">${escapeHtml(story.title)}</span>
+      </button>`;
+  }).join('');
+
+  const btn = document.getElementById('storyLoadMoreBtn');
+  if (btn) btn.style.display = paged.length < total ? 'block' : 'none';
+}
