+let currentPin = '';
+function showPinOverlay() {
+  currentPin = '';
+  const root = document.getElementById('sihyeonPlayOS');
+  const div = document.createElement('div');
+  div.className = 'pin-overlay';
+  div.id = 'pinOverlay';
+  div.innerHTML = `
+    <div class="pin-box">
+      <div class="pin-title">🔒 부모님 확인</div>
+      <div class="pin-display" id="pinDisplay">_ _ _ _</div>
+      <div class="pin-numpad">
+        ${[1,2,3,4,5,6,7,8,9].map(n => `<button class="pin-btn" onclick="handlePinPad(${n})">${n}</button>`).join('')}
+        <button class="pin-btn" onclick="handlePinPad('C')">C</button>
+        <button class="pin-btn" onclick="handlePinPad(0)">0</button>
+        <button class="pin-btn" onclick="closePinOverlay()">닫기</button>
+      </div>
+    </div>
+  `;
+  root.appendChild(div);
+}
+
+function closePinOverlay() {
+  const el = document.getElementById('pinOverlay');
+  if(el) el.remove();
+}
+
+function handlePinPad(val) {
+  if(val === 'C') { currentPin = ''; }
+  else if(currentPin.length < 4) { currentPin += val; }
+
+  const display = document.getElementById('pinDisplay');
+  if(display) {
+    display.textContent = currentPin.padEnd(4, '_').split('').join(' ');
+  }
+
+  if(currentPin.length === 4) {
+    if(currentPin === '0000') {
+      closePinOverlay();
+      renderParentDashboard();
+    } else {
+      display.textContent = '다시 입력';
+      display.style.color = 'red';
+      setTimeout(() => {
+         currentPin = '';
+         display.textContent = '_ _ _ _';
+         display.style.color = '';
+      }, 800);
+    }
+  }
+}
+
+function renderParentDashboard() {
+  const root = document.getElementById('sihyeonPlayOS');
+  const todayStr = getToday();
+  const todayLog = db.parentLog?.daily[todayStr] || { totalMinutes: 0, timerCount: 0, landsVisited: [], storiesWatched: [] };
+
+  const last7Days = [];
+  let maxMins = 1;
+  for(let i=6; i>=0; i--) {
+    const d = new Date();
+    d.setDate(d.getDate() - i);
+    const dStr = d.toISOString().slice(0,10);
+    const mins = db.parentLog?.daily[dStr]?.totalMinutes || 0;
+    if(mins > maxMins) maxMins = mins;
+    last7Days.push({ date: `${d.getMonth()+1}/${d.getDate()}`, mins });
+  }
+
+  root.innerHTML = `
+    <div class="parent-dash-screen">
+      <div class="dash-header">
+        <div class="dash-title">🔒 시현이 사용 현황</div>
+        <button class="dash-close-btn" onclick="renderWorldMapHome()">닫기</button>
+      </div>
+      <div class="dash-content">
+
+        <div class="summary-grid">
+          <div class="summary-item">
+            <div class="summary-val">${todayLog.totalMinutes}분</div>
+            <div class="summary-lbl">오늘 사용 시간</div>
+          </div>
+          <div class="summary-item">
+            <div class="summary-val">${todayLog.timerCount}회</div>
+            <div class="summary-lbl">오늘 타이머 사용</div>
+          </div>
+          <div class="summary-item" style="grid-column: span 2;">
+            <div class="summary-val">Lv.${db.progress.level}</div>
+            <div class="summary-lbl">현재 게임 레벨 (경험치: ${db.progress.exp}%)</div>
+          </div>
+        </div>
+
+        <div class="dash-card">
+          <div class="dash-card-title">오늘 방문한 랜드</div>
+          <div class="visited-lands">
+            ${todayLog.landsVisited.length ? todayLog.landsVisited.map(l => `<span class="visited-chip">${l}</span>`).join('') : '<span class="story-empty-lbl">아직 방문한 랜드가 없어요.</span>'}
+          </div>
+        </div>
+
+        <div class="dash-card">
+          <div class="dash-card-title">오늘 읽은 동화</div>
+          <ul class="story-list">
+            ${todayLog.storiesWatched.length ? todayLog.storiesWatched.map(s => `<li>📖 ${escapeHtml(s)}</li>`).join('') : '<li class="story-empty-lbl">아직 읽은 동화가 없어요.</li>'}
+          </ul>
+        </div>
+
+        <div class="dash-card">
+          <div class="dash-card-title">최근 7일 사용 시간 (분)</div>
+          <div class="chart-container">
+            ${last7Days.map(d => {
+              const h = Math.max((d.mins / maxMins) * 100, 5);
+              return `
+                <div class="chart-col">
+                  <div class="chart-bar-wrap">
+                    <div class="chart-val" style="bottom: ${h}%; margin-bottom: 4px;">${d.mins}</div>
+                    <div class="chart-bar" style="height: ${d.mins === 0 ? 0 : h}%;"></div>
+                  </div>
+                  <div class="chart-lbl">${d.date}</div>
+                </div>
+              `;
+            }).join('')}
+          </div>
+        </div>
+
+      </div>
+    </div>
+  `;
+}
